    public long xorshift1024star() {
        long s0 = this.r[this.p];
        this.p = this.p + 1 & 0xF;
        long s1 = this.r[this.p];
        s1 ^= s1 << 31;
        s1 ^= s1 >>> 11;
        s0 ^= s0 >>> 30;
        this.r[this.p] = s0 ^ s1;
        return this.r[this.p] * 1181783497276652981L;
